messages.content:
{
  "children": [
    {
      "name": "RegisterPatient",
      "purpose": "Validate required fields, create patient record, and generate unique patient_id",
      "behavior": "Check that name, dob, contact, insurance are present; generate a new patient_id; store patient data in patients database; return success with patient_id",
      "boundary": {
        "in_scope": [
          "field validation",
          "patient_id generation",
          "database write"
        ],
        "out_of_scope": [
          "appointment booking",
          "record retrieval",
          "profile updates"
        ]
      },
      "semantic_inputs": [
        {
          "name": "patient_data",
          "description": "Patient payload with name, dob, contact, insurance",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "patient_result",
          "description": "Result dict with success, data (patient_id), message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "patient_data contains name, dob, contact, insurance"
      ],
      "postconditions": [
        "patient record exists in patients database"
      ],
      "guarantees": [
        "patient_id is unique",
        "patient record is persisted"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "BookAppointment",
      "purpose": "Check patient exists, check doctor availability, create appointment record, send confirmation",
      "behavior": "Verify patient_id exists in patients; check doctor availability at requested time; create appointment record in appointments database; return success with appointment_id",
      "boundary": {
        "in_scope": [
          "patient existence check",
          "doctor availability check",
          "appointment creation"
        ],
        "out_of_scope": [
          "patient registration",
          "record retrieval",
          "profile updates"
        ]
      },
      "semantic_inputs": [
        {
          "name": "patient_data",
          "description": "Patient payload with patient_id, doctor_id, appointment_time",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "patient_result",
          "description": "Result dict with success, data (appointment_id), message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "patient_id exists in patients",
        "appointment_time is in the future"
      ],
      "postconditions": [
        "appointment record exists in appointments database"
      ],
      "guarantees": [
        "appointment is not double-booked",
        "time is validated"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "RetrieveRecords",
      "purpose": "Retrieve all medical records for a patient, sorted by date descending",
      "behavior": "Query records database for all records matching patient_id; sort by timestamp descending; return list of records",
      "boundary": {
        "in_scope": [
          "record retrieval",
          "sorting"
        ],
        "out_of_scope": [
          "record creation",
          "record modification",
          "other operations"
        ]
      },
      "semantic_inputs": [
        {
          "name": "patient_data",
          "description": "Patient payload with patient_id",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "patient_result",
          "description": "Result dict with success, data (list of records), message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "patient_id exists in patients"
      ],
      "postconditions": [
        "records are returned sorted by date descending"
      ],
      "guarantees": [
        "records are read-only",
        "no side effects"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "UpdatePatientProfile",
      "purpose": "Update patient profile fields; if insurance changed, validate against external system",
      "behavior": "Update patient record in patients database with provided fields; if insurance field is present and different from current, validate via external system before saving; return success",
      "boundary": {
        "in_scope": [
          "profile field update",
          "insurance validation"
        ],
        "out_of_scope": [
          "registration",
          "appointment booking",
          "record retrieval"
        ]
      },
      "semantic_inputs": [
        {
          "name": "patient_data",
          "description": "Patient payload with patient_id and fields to update",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "patient_result",
          "description": "Result dict with success, data (updated fields), message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "patient_id exists in patients"
      ],
      "postconditions": [
        "patient record is updated in database"
      ],
      "guarantees": [
        "insurance validation occurs if changed",
        "other fields updated atomically"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "Each child handles one of the four commands independently, covering the full responsibility of the parent. The parent routes based on command to the appropriate child, ensuring no sibling calls.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {
      "from": "parent",
      "to": "RegisterPatient",
      "data": "command='register', patient_data",
      "note": "route to register handler"
    },
    {
      "from": "parent",
      "to": "BookAppointment",
      "data": "command='book', patient_data",
      "note": "route to book handler"
    },
    {
      "from": "parent",
      "to": "RetrieveRecords",
      "data": "command='records', patient_data",
      "note": "route to records handler"
    },
    {
      "from": "parent",
      "to": "UpdatePatientProfile",
      "data": "command='update', patient_data",
      "note": "route to update handler"
    },
    {
      "from": "RegisterPatient",
      "to": "parent",
      "data": "patient_result",
      "note": "return result"
    },
    {
      "from": "BookAppointment",
      "to": "parent",
      "data": "patient_result",
      "note": "return result"
    },
    {
      "from": "RetrieveRecords",
      "to": "parent",
      "data": "patient_result",
      "note": "return result"
    },
    {
      "from": "UpdatePatientProfile",
      "to": "parent",
      "data": "patient_result",
      "note": "return result"
    }
  ]
}
